Bash(cd "D:/_bootstrap/slides-grab" && node --input-type=module -e "
import archiver from 'archiver';

const archive = archiver\('zip', { zlib: { level: 6 } }\);
const chunks = [];
archive.on\('data', \(chunk\) => chunks.push\(chunk\)\);
const zipDone = new Promise\(\(resolve, reject\) => {
  archive.on\('end', \(\) => resolve\(Buffer.concat\(chunks\)\)\);
  archive.on\('error', reject\);
}\);

archive.append\(Buffer.from\('<svg>test1</svg>', 'utf-8'\), { name: 'slide-01.svg' }\);
archive.append\(Buffer.from\('<svg>test2</svg>', 'utf-8'\), { name: 'slide-02.svg' }\);
archive.finalize\(\);

const buf = await zipDone;
console.log\('ZIP buffer size:', buf.length, 'bytes'\);
console.log\('Is Buffer:', Buffer.isBuffer\(buf\)\);
console.log\('First bytes \(PK header\):', buf[0], buf[1]\); // should be 80, 75 \(PK\)
" 2>&1)

